mapper.insert:
    INSERT INTO MOVIE
	( MOVIE_ID
	, POSTER_URL
	, TITLE
	, MOVIE_RATING
	, OPEN_DATE
	, OPEN_COUNTRY
	, RUNNING_TIME
	, INTRODUCE
	, SYSNOPSIS
	, ORIGINAL_TITLE
	, STATE
	, "LANGUAGE"
	, BUDGET
	, PROFIT)
	VALUES
	( 'MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIE_PK.NEXTVAL, 6, '0')
	, #{posterUrl}
	, #{title}
	, #{movieRating}
	, #{openDate}
	, #{openCountry}
	, #{runningTime}
	, #{introduce}
	, #{sysnopsis}
	, #{originalTitle}
	, #{state}
	, #{languagel}
	, #{budget}
	, #{profit})
